parameters.jsCode:
// Combine Lead and Contact records into a unified format
const allItems = $input.all();
const records = [];

for (const item of allItems) {
  const data = item.json;

  // Skip the wrapper object if it has no records (empty query result)
  if (data.totalSize !== undefined) continue;

  // Determine if this is a Lead or Contact based on available fields
  const isLead = data.Company !== undefined || data.Status !== undefined;

  if (isLead) {
    const locationStr = [data.City, data.State].filter(Boolean).join(', ') || data.PostalCode || '';
    records.push({
      type: 'lead',
      objectType: 'Lead',
      id: data.Id,
      name: data.Name || `${data.FirstName || ''} ${data.LastName || ''}`.trim(),
      practice: data.Company || 'Unknown Practice',
      phone: data.Phone || 'N/A',
      email: data.Email || 'N/A',
      city: data.City || '',
      state: data.State || '',
      zip: data.PostalCode || '',
      location: locationStr,
      website: data.Website || '',
      repName: data.Owner?.Name || 'Unassigned',
      repId: data.OwnerId || '',
      source: data.LeadSource || 'Unknown',
      createdDate: data.CreatedDate
    });
  } else {
    // Contact re-engagement
    const account = data.Account || {};
    records.push({
      type: 'contact',
      objectType: 'Contact',
      id: data.Id,
      name: data.Name || `${data.FirstName || ''} ${data.LastName || ''}`.trim(),
      practice: account.Name || 'Unknown Practice',
      phone: data.Phone || 'N/A',
      email: data.Email || 'N/A',
      city: '',
      state: '',
      zip: '',
      location: '',
      website: '',
      repName: account.Owner?.Name || 'Unassigned',
      repId: account.OwnerId || '',
      accountId: data.AccountId,
      accountStatus: account.Status__c || 'Unknown',
      tciStatus: account.TCI_Status__c || 'None',
      source: 'Re-Engagement'
    });
  }
}

if (records.length === 0) {
  return [{ json: { hasRecords: false, count: 0 } }];
}

return records.map(r => ({ json: { ...r, hasRecords: true } }));

