parameters.jsCode:
const r = $('Process One at a Time').item.json;

const trigger = r.type === 'lead'
  ? '🎯 *New Lead — Prophet Research Ready*'
  : '🔄 *Re-Engagement Alert — Practice Revisiting PDM*';

// Build location cleanly — never duplicate zip when city/state are blank
const locationParts = [];
if (r.city) locationParts.push(r.city);
if (r.state) locationParts.push(r.state);
if (r.zip) locationParts.push(r.zip);
const locationDisplay = locationParts.length > 0 ? locationParts.join(', ') : null;

// Command uses zip for geographic precision if available
const command = r.zip
  ? `sf_research_prospect for ${r.practice} in ${r.zip}`
  : `sf_research_prospect for ${r.practice}`;

const lines = [trigger, ''];
lines.push(`*Practice:* ${r.practice}`);
lines.push(`*Contact:* ${r.name}`);
lines.push(`*Phone:* ${r.phone}`);
lines.push(`*Email:* ${r.email}`);
if (locationDisplay) lines.push(`*Location:* ${locationDisplay}`);
if (r.website) lines.push(`*Website:* ${r.website}`);
if (r.source && r.source !== 'Unknown') lines.push(`*Source:* ${r.source}`);
if (r.type === 'contact') lines.push(`*Account Status:* ${r.accountStatus} | TCI: ${r.tciStatus}`);
lines.push(`*Assigned Rep:* ${r.repName}`);
lines.push('');
lines.push('*Run Prophet now in Claude Desktop:*');
lines.push(`\`${command}\``);
lines.push('');
lines.push('_Prophet delivers full market brief, competitive landscape, SEO gaps, and Gamma deck in 2 minutes._');

return [{ json: { text: lines.join('\n') } }];
